  function formFields(project={}){const ts=project.musicalSettings?.timeSignature;const signature=ts?`${ts.numerator}/${ts.denominator}`:'4/4';const key=project.musicalSettings?.key??'';const signatures=['2/4','3/4','4/4','5/4','6/8','7/8','12/8'];const keys=['C','C#','Db','D','D#','Eb','E','F','F#','Gb','G','G#','Ab','A','A#','Bb','B','Cm','C#m','Dbm','Dm','D#m','Ebm','Em','Fm','F#m','Gbm','Gm','G#m','Abm','Am','A#m','Bbm','Bm','C♯/D♭','D♯/E♭','F♯/G♭','G♯/A♭','A♯/B♭'];return `<div class="music-form-grid"><label for="msProjectName">プロジェクト名 <span aria-hidden="true">*</span><input id="msProjectName" name="projectName" required maxlength="120" value="${escapeHtml(project.projectName||'')}"></label><label for="msSongTitle">曲名<input id="msSongTitle" name="songTitle" maxlength="120" value="${escapeHtml(project.songTitle||'')}"></label><label class="music-span-2" for="msPurpose">制作目的または使用作品<input id="msPurpose" name="purpose" maxlength="240" value="${escapeHtml(project.purpose||'')}"></label><label for="msBpm">BPM<input id="msBpm" name="bpm" type="number" min="20" max="400" inputmode="decimal" step="0.1" required value="${escapeHtml(project.musicalSettings?.bpm??120)}"></label><label for="msTimeSignature">拍子<select id="msTimeSignature" name="timeSignature">${signatures.map(value=>`<option ${signature===value?'selected':''}>${value}</option>`).join('')}</select></label><label for="msKey">キー<select id="msKey" name="key"><option value="">未設定</option>${keys.map(value=>`<option ${key===value?'selected':''}>${value}</option>`).join('')}</select></label><label for="msStatus">制作状態<select id="msStatus" name="status">${Object.entries(PROJECT_STATUS_LABELS).map(([value,label])=>`<option value="${value}" ${(project.status||'idea')===value?'selected':''}>${label}</option>`).join('')}</select></label><label class="music-span-2" for="msProductionNotes">制作メモ<textarea id="msProductionNotes" name="productionNotes" rows="6" maxlength="10000">${escapeHtml(project.productionNotes||'')}</textarea></label></div>`}
  function createView(){const d=state.settings?.projectDefaults||defaultSettings().projectDefaults;const project=makeProject({projectName:'',bpm:d.bpm,timeSignature:d.timeSignature,key:d.key,status:d.status,purpose:d.purpose,productionNotes:d.notes});return `<main class="music-studio-shell music-project-page" aria-labelledby="musicCreateTitle">${backButton()}${noticeView()}<section class="music-project-panel"><p class="music-kicker">New project</p><h1 id="musicCreateTitle">新しい音楽プロジェクト</h1><p class="music-lead">入力内容はMusic Studio専用領域へ保存されます。</p><form id="musicProjectForm" oninput="MusicStudio.markDirty()" onsubmit="MusicStudio.submitCreate(event)">${formFields(project)}<div class="music-form-actions"><button class="music-primary" type="submit">作成して保存</button><button class="music-secondary" type="button" onclick="MusicStudio.cancelEdit()">キャンセル</button><span class="music-save-state" data-dirty="${state.dirty}" aria-live="polite">${state.dirty?'未保存の変更があります':'未変更'}</span></div></form></section></main>`}
  function projectRow(project){return `<article class="music-project-row"><div><h2>${escapeHtml(project.projectName)}</h2><p>${escapeHtml(project.songTitle||'曲名未設定')} · ${escapeHtml(PROJECT_STATUS_LABELS[project.status]||project.status)} · BPM ${escapeHtml(project.musicalSettings?.bpm)} · ${escapeHtml(project.musicalSettings?.key||'キー未設定')}</p><small>最終更新：${formatDate(project.updatedAt)}</small></div><button class="music-primary" onclick="MusicStudio.openProject('${escapeHtml(project.projectId)}')">開く</button></article>`}
  function listView(){const query=state.search.trim().toLocaleLowerCase('ja');const items=state.projects.filter(project=>!query||[project.projectName,project.songTitle,project.purpose].some(value=>String(value||'').toLocaleLowerCase('ja').includes(query))).sort((a,b)=>(b.updatedAt||'').localeCompare(a.updatedAt||''));return `<main class="music-studio-shell music-project-page" aria-labelledby="musicProjectsTitle">${backButton()}${noticeView()}<section class="music-project-panel"><div class="music-section-heading"><div><p class="music-kicker">Projects</p><h1 id="musicProjectsTitle">音楽プロジェクト</h1></div><button class="music-primary" onclick="MusicStudio.goNew()">＋ 新規作成</button></div><label class="music-search" for="musicProjectSearch">プロジェクトを検索<input id="musicProjectSearch" type="search" value="${escapeHtml(state.search)}" placeholder="プロジェクト名・曲名・使用作品" oninput="MusicStudio.searchProjects(this.value)"></label><div class="music-project-list">${state.loaded?(items.map(projectRow).join('')||`<div class="music-empty"><p>${query?'検索条件に一致するプロジェクトはありません。':'プロジェクトはまだありません。'}</p><button class="music-primary" onclick="MusicStudio.goNew()">最初のプロジェクトを作る</button></div>`):'<p class="music-empty">プロジェクトを読み込んでいます…</p>'}</div><div class="music-import-box"><label for="musicProjectImport">JSONから読み込む<input id="musicProjectImport" type="file" accept="application/json,.json" onchange="MusicStudio.importFile(this.files[0]);this.value=''" hidden></label><button class="music-secondary" onclick="document.querySelector('#musicProjectImport').click()">JSONを読み込む</button><p>既存データを消さず、Version 1形式を新規または複製として追加します。</p></div></section></main>`}
  function editView(id){const project=state.projects.find(item=>item.projectId===id);if(!project)return `<main class="music-studio-shell music-project-page">${backButton('プロジェクト一覧へ戻る')}<div class="music-empty"><h1>プロジェクトが見つかりません</h1><p>削除済みか、URLが正しくない可能性があります。</p><button class="music-primary" onclick="MusicStudio.goProjects()">一覧へ戻る</button></div></main>`;return `<main class="music-studio-shell music-project-page" aria-labelledby="musicEditTitle"><button class="music-secondary music-back" onclick="MusicStudio.goProjects()">← プロジェクト一覧へ戻る</button>${noticeView()}<section class="music-project-panel"><div class="music-section-heading"><div><p class="music-kicker">Project</p><h1 id="musicEditTitle">${escapeHtml(project.projectName)}</h1><p>作成：${formatDate(project.createdAt)} / 更新：${formatDate(project.updatedAt)} / Revision ${project.revision}</p></div></div><form id="musicProjectForm" oninput="MusicStudio.markDirty()" onsubmit="MusicStudio.submitEdit(event,'${escapeHtml(project.projectId)}')">${formFields(project)}<div class="music-form-actions"><button class="music-primary" type="submit">変更を保存</button><button class="music-secondary" type="button" onclick="MusicStudio.cancelEdit('${escapeHtml(project.projectId)}')">キャンセル</button><span class="music-save-state" data-dirty="${state.dirty}">${state.dirty?'未保存の変更があります':'保存済み'}</span></div></form><div class="music-project-tools"><button class="music-secondary" onclick="MusicStudio.duplicateProject('${escapeHtml(project.projectId)}')">複製</button><button class="music-secondary" onclick="MusicStudio.exportProject('${escapeHtml(project.projectId)}')">JSON書き出し</button><button class="music-danger" onclick="MusicStudio.askDelete('${escapeHtml(project.projectId)}')">このプロジェクトを削除</button></div></section></main>`}
  const settingSections=[['general','一般'],['projectDefaults','プロジェクト初期値'],['autosave','自動保存'],['midi','MIDI'],['logicPro','Logic Pro X'],['fileNaming','ファイル名'],['backup','バックアップ'],['display','表示'],['accessibility','アクセシビリティ'],['privacy','プライバシー'],['appInfo','アプリ情報'],['experimental','詳細設定']];
  function checked(value){return value?' checked':''}
  function option(value,current,label=value){return `<option value="${escapeHtml(value)}"${String(value)===String(current)?' selected':''}>${escapeHtml(label)}</option>`}
  function toggle(name,label,value,help='',disabled=false){return `<label class="music-toggle"><input type="checkbox" name="${name}"${checked(value)}${disabled?' disabled':''}><span><b>${escapeHtml(label)}</b>${help?`<small>${escapeHtml(help)}</small>`:''}</span></label>`}
  function settingSection(id,title,body){return `<section id="ms-setting-${id}" class="music-setting-section" aria-labelledby="ms-setting-${id}-title"><h2 id="ms-setting-${id}-title">${title}</h2>${body}</section>`}
  function settingsView(){const s=state.settingsDraft||state.settings||defaultSettings();const nav=settingSections.map(([id,label])=>`<a href="#ms-setting-${id}">${label}</a>`).join('');return `<main class="music-studio-shell music-settings-page" aria-labelledby="musicSettingsTitle">${backButton()}${noticeView()}<header class="music-page-header"><p class="music-kicker">MS-03 / Settings foundation</p><h1 id="musicSettingsTitle">Music Studio設定</h1><p>端末内のMusic Studio専用領域だけに保存します。プロジェクトや他アプリのデータは初期化しません。</p><span class="music-save-state" data-status="${state.saveStatus}" aria-live="polite">${state.dirty?'未保存の変更があります':state.saveStatus==='saving'?'保存中':state.saveStatus==='error'?'保存に失敗しました':'保存しました'}</span></header><div class="music-settings-layout"><nav class="music-settings-nav" aria-label="設定分類">${nav}</nav><form id="musicSettingsForm" class="music-settings-form" oninput="MusicStudio.markSettingsDirty()" onsubmit="MusicStudio.saveSettingsForm(event)">
  ${settingSection('general','一般',`<div class="music-form-grid"><label>言語<select name="general.language">${option('ja',s.general.language,'日本語')}</select></label><label>日付表示<select name="general.dateFormat">${option('ja-JP',s.general.dateFormat,'日本向け')}</select></label></div>${toggle('general.confirmDialogs','確認ダイアログ',s.general.confirmDialogs)}${toggle('general.notifications','通知',s.general.notifications)}${toggle('general.confirmDangerousActions','危険操作の確認',s.general.confirmDangerousActions)}`)}
  ${settingSection('projectDefaults','プロジェクト初期値',`<div class="music-form-grid"><label>BPM<input type="number" name="projectDefaults.bpm" min="20" max="400" step="0.1" value="${s.projectDefaults.bpm}" required></label><label>拍子<select name="projectDefaults.timeSignature">${['4/4','3/4','6/8','5/4','7/8','2/4','12/8'].map(v=>option(v,s.projectDefaults.timeSignature)).join('')}</select></label><label>キー<select name="projectDefaults.key">${option('',s.projectDefaults.key??'','未設定')}${['C','C#','Db','D','D#','Eb','E','F','F#','Gb','G','G#','Ab','A','A#','Bb','B','Cm','Dm','Em','Fm','Gm','Am','Bm'].map(v=>option(v,s.projectDefaults.key)).join('')}</select></label><label>制作状態<select name="projectDefaults.status">${Object.entries(PROJECT_STATUS_LABELS).map(([v,l])=>option(v,s.projectDefaults.status,l)).join('')}</select></label><label class="music-span-2">制作目的<input name="projectDefaults.purpose" maxlength="240" value="${escapeHtml(s.projectDefaults.purpose)}"></label><label class="music-span-2">制作メモ<textarea name="projectDefaults.notes" maxlength="10000" rows="3">${escapeHtml(s.projectDefaults.notes)}</textarea></label></div><p class="music-help">変更後に作成する新規プロジェクトだけへ反映します。</p>`)}
  ${settingSection('autosave','自動保存',`${toggle('autosave.enabled','自動保存を有効にする',s.autosave.enabled)}<div class="music-form-grid"><label>定期保存間隔（秒）<input type="number" name="autosave.intervalSeconds" min="15" max="3600" value="${s.autosave.intervalSeconds}"></label><label>入力終了後の遅延（秒）<input type="number" name="autosave.idleDelaySeconds" min="1" max="30" value="${s.autosave.idleDelaySeconds}"></label></div><p class="music-help">手動保存は常に利用できます。保存中・保存済み・未保存・失敗を文字でも表示します。</p>`)}
  ${settingSection('midi','MIDI',`<div class="music-form-grid"><label>標準MIDI形式<select name="midi.fileType">${option(1,s.midi.fileType,'Type 1')}${option(0,s.midi.fileType,'Type 0')}</select></label><label>PPQ<input type="number" name="midi.ppq" min="24" max="9600" value="${s.midi.ppq}"></label><label>クオンタイズ<select name="midi.quantize">${['1/4','1/8','1/16','1/32'].map(v=>option(v,s.midi.quantize)).join('')}</select></label><label>ベロシティ<input type="number" name="midi.velocity" min="1" max="127" value="${s.midi.velocity}"></label><label>MIDIチャンネル<input type="number" name="midi.channel" min="1" max="16" value="${s.midi.channel}"></label></div>${toggle('midi.autoChannel','チャンネルを自動割当',s.midi.autoChannel)}${toggle('midi.useTrackNames','トラック名を利用',s.midi.useTrackNames)}${toggle('midi.includeTempo','BPM情報を含める',s.midi.includeTempo)}${toggle('midi.includeTimeSignature','拍子情報を含める',s.midi.includeTimeSignature)}${toggle('midi.omitEmptyTracks','空トラックを書き出さない',s.midi.omitEmptyTracks)}<p class="music-help">今回は設定保存のみで、MIDI生成は行いません。</p>`)}
  ${settingSection('logicPro','Logic Pro X',`<div class="music-form-grid"><label>連携方式<select name="logicPro.method">${option('file-export',s.logicPro.method,'ファイル書き出し')}</select></label><label>オーディオ参照<select name="logicPro.audioReferences">${option('external',s.logicPro.audioReferences,'外部ファイル')}</select></label></div>${toggle('logicPro.preferMidi','MIDI書き出しを優先',s.logicPro.preferMidi)}${toggle('logicPro.showInstructions','書き出し後に手順を表示',s.logicPro.showInstructions)}<p class="music-help">自動起動と直接操作は常に無効です。Intel Macでも安全なファイル受け渡しだけを前提にします。</p>`)}
  ${settingSection('fileNaming','ファイル名',`<div class="music-form-grid"><label class="music-span-2">テンプレート<input name="fileNaming.template" maxlength="200" value="${escapeHtml(s.fileNaming.template)}"><small>{projectName} {songTitle} {type} {date} {time} {version}</small></label><label>最大文字数<input type="number" name="fileNaming.maxLength" min="20" max="200" value="${s.fileNaming.maxLength}"></label><label>空欄時の名前<input name="fileNaming.fallback" maxlength="80" value="${escapeHtml(s.fileNaming.fallback)}"></label></div><p class="music-help">使用できない文字は安全なハイフンへ置換します。未対応トークンは保存時に拒否します。</p><output id="musicFileNamePreview" class="music-filename-preview">プレビュー：${escapeHtml(renderFileName(s.fileNaming.template,{projectName:'夜空のプロジェクト',songTitle:'星明かり',type:'midi'},{maxLength:s.fileNaming.maxLength,fallback:s.fileNaming.fallback,date:'2026-07-20T21:30:00.000Z'}).filename)}.json</output>`)}
  ${settingSection('backup','バックアップ設定',`${toggle('backup.automaticEnabled','自動バックアップ',s.backup.automaticEnabled,'初期状態は無効です')}<div class="music-form-grid"><label>間隔（時間）<input type="number" name="backup.intervalHours" min="1" max="720" value="${s.backup.intervalHours}"></label><label>最大保持件数<input type="number" name="backup.maxCopies" min="1" max="100" value="${s.backup.maxCopies}"></label></div><p class="music-help">ブラウザからの手動JSONバックアップを提供します。クラウド同期と一括削除はありません。</p><button class="music-secondary" type="button" onclick="MusicStudio.goBackup()">バックアップ管理を開く</button>`)}
  ${settingSection('display','表示',`<div class="music-form-grid"><label>テーマ<select name="display.theme">${option('music-studio',s.display.theme,'Music Studio')}</select></label><label>文字サイズ<select name="display.fontSize">${option('standard',s.display.fontSize,'標準')}${option('large',s.display.fontSize,'大きい')}</select></label><label>カード密度<select name="display.cardDensity">${option('standard',s.display.cardDensity,'標準')}${option('compact',s.display.cardDensity,'コンパクト')}</select></label><label>動きの軽減<select name="display.reducedMotion">${option('system',s.display.reducedMotion,'OS設定に従う')}${option('reduce',s.display.reducedMotion,'軽減する')}</select></label></div>`)}
  ${settingSection('accessibility','アクセシビリティ',`${toggle('accessibility.focusVisible','フォーカス表示',s.accessibility.focusVisible)}${toggle('accessibility.keyboard','キーボード操作',s.accessibility.keyboard)}${toggle('accessibility.textStatus','状態を文字でも表示',s.accessibility.textStatus)}`)}
  ${settingSection('privacy','プライバシー',`<p><b>保存場所：</b>端末内のMusic Studio専用IndexedDB</p>${toggle('privacy.externalTransfer','外部送信',false,'安全のため無効固定',true)}${toggle('privacy.analytics','解析送信',false,'安全のため無効固定',true)}${toggle('privacy.cloudSync','クラウド同期',false,'未実装',true)}`)}
  ${settingSection('appInfo','アプリ情報',`<dl class="music-info-list"><div><dt>アプリ名</dt><dd>Music Studio</dd></div><div><dt>所属</dt><dd>Dream Architect Studio</dd></div><div><dt>現在のバージョン</dt><dd>${APP_VERSION}</dd></div><div><dt>開発段階</dt><dd>MS-03N 設定・保存・バックアップ基盤（ティア確認待ち）</dd></div><div><dt>設定形式</dt><dd>${SETTINGS_FORMAT} Version ${SETTINGS_VERSION}</dd></div><div><dt>プロジェクト形式</dt><dd>${FORMAT} Version 1</dd></div><div><dt>バックアップ形式</dt><dd>${BACKUP_FORMAT} Version ${BACKUP_VERSION}</dd></div><div><dt>保存場所</dt><dd>端末内</dd></div><div><dt>外部送信</dt><dd>行いません</dd></div></dl><p>単体アプリ化を前提とし、端末内保存のみを行います。ライセンス情報とCHANGELOGは同梱文書を参照してください。</p><p><a href="./docs/music-studio/MS-00C_LICENSE_REGISTER.md">ライセンス情報</a> · <a href="./CHANGELOG.md">CHANGELOG</a></p>`)}
  ${settingSection('experimental','詳細設定',`<p>将来機能用です。販売版で不安定機能を誤って有効化しないため、すべて無効です。</p>${toggle('experimental.enabled','実験機能',false,'現在は変更できません',true)}`)}
  <div class="music-sticky-actions"><button class="music-primary" type="submit">変更を保存</button><button class="music-secondary" type="button" onclick="MusicStudio.discardSettings()">変更を破棄</button><button class="music-secondary" type="button" onclick="MusicStudio.resetSettings()">初期値に戻す</button><button class="music-secondary" type="button" onclick="MusicStudio.exportSettings()">設定を書き出す</button><input id="musicSettingsImport" type="file" accept="application/json,.json" hidden onchange="MusicStudio.importSettingsFile(this.files[0]);this.value=''"><button class="music-secondary" type="button" onclick="document.querySelector('#musicSettingsImport').click()">設定を読み込む</button></div></form></div></main>`}
  function backupView(){const preview=state.backupPreview;const automatic=state.autoBackups.map(item=>`<article class="music-auto-backup-row"><div><b>${formatDate(item.createdAt)}</b><small>プロジェクト ${item.snapshot?.projects?.length||0}件 · ${escapeHtml(item.sizeLabel||'容量不明')}</small></div><button class="music-secondary" onclick="MusicStudio.restoreAutoBackup('${escapeHtml(item.backupId)}')">この自動バックアップを復元</button></article>`).join('')||'<p class="music-empty">自動バックアップはまだありません。</p>';return `<main class="music-studio-shell music-settings-page" aria-labelledby="musicBackupTitle">${backButton()}${noticeView()}<header class="music-page-header"><p class="music-kicker">Local JSON backup</p><h1 id="musicBackupTitle">Music Studioバックアップ</h1><p>対象：設定1件、プロジェクト${state.projects.length}件、参照ファイルのメタ情報。MIDI・音声・画像本体は含みません。</p></header><section class="music-setting-section"><h2>手動バックアップを書き出す</h2><p>既存データを変更せず、Music Studio全体をVersion 1 JSONへまとめます。手動ファイルは自動整理の対象外です。</p><button class="music-primary" onclick="MusicStudio.exportBackup()">全体バックアップを書き出す</button></section><section class="music-setting-section"><h2>バックアップを検証・復元</h2><input id="musicBackupImport" type="file" accept="application/json,.json" hidden onchange="MusicStudio.previewBackupFile(this.files[0]);this.value=''"><button class="music-secondary" onclick="document.querySelector('#musicBackupImport').click()">バックアップJSONを選択</button>${preview?`<div class="music-backup-preview" role="status"><h3>復元前の概要</h3><p>作成：${formatDate(preview.metadata.createdAt)} / プロジェクト ${preview.projects.length}件 / 参照 ${preview.references?.length||0}件</p><label><input id="restoreSettings" type="checkbox" checked> 設定を復元</label><label><input id="restoreProjects" type="checkbox" checked> プロジェクトを追加・統合</label><p>同じIDは新しいIDで追加します。不正な項目はスキップして件数を報告します。既存データは削除・上書きせず、復元前に現在状態を安全コピーとしてダウンロードします。</p><button class="music-primary" onclick="MusicStudio.restorePreviewedBackup()">内容を確認して復元</button><button class="music-secondary" onclick="MusicStudio.clearBackupPreview()">キャンセル</button></div>`:''}</section><section class="music-setting-section"><div class="music-section-heading"><div><h2>端末内の自動バックアップ</h2><p>Music Studioを開いた時だけ期限を確認します。バックグラウンド常駐は行いません。</p></div><button class="music-secondary" onclick="MusicStudio.checkAutoBackupNow()">期限を確認</button></div><div class="music-auto-backup-list">${automatic}</div></section></main>`}
  const LOGIC_IMPORT_STEPS=['Music StudioでMIDIを書き出します（MIDI Composer実装後に利用可能）。','Macのダウンロード先にある .mid ファイルを確認します。','Logic Proを開き、新規または既存プロジェクトを開きます。','Logic Proの「ファイル」>「読み込む」>「MIDIファイル」を選ぶか、Finderからトラック領域へドラッグします。','テンポ、拍子、マーカー、トラック名と開始位置を確認します。','各トラックへ必要な音源を割り当て、Logic Pro側でプロジェクトを保存します。'];
  function settingSummary(){const all=state.settings||defaultSettings(),m=all.midi,l=all.logicPro,n=all.fileNaming;return `<dl class="music-info-list"><div><dt>連携方式</dt><dd>${l.method==='file-export'?'ファイルの手動受け渡し':'安全な既定値へ補正'}</dd></div><div><dt>優先形式</dt><dd>標準MIDI / Type ${m.fileType} / PPQ ${m.ppq}</dd></div><div><dt>含める情報</dt><dd>トラック名 ${m.useTrackNames?'あり':'なし'}、BPM ${m.includeTempo?'あり':'なし'}、拍子 ${m.includeTimeSignature?'あり':'なし'}、channel ${m.autoChannel?'自動':m.channel}</dd></div><div><dt>ノート既定値</dt><dd>${m.quantize}、velocity ${m.velocity}、空トラック ${m.omitEmptyTracks?'除外':'含む'}</dd></div><div><dt>音声</dt><dd>外部参照（本体は保存しない）</dd></div><div><dt>ファイル名</dt><dd>${escapeHtml(n.template)}</dd></div><div><dt>安全制限</dt><dd>自動起動なし / 直接操作なし / 外部送信なし</dd></div></dl>`}
  function logicProView(){return `<main class="music-studio-shell music-logic-page" aria-labelledby="logicProTitle">${backButton()}${noticeView()}<header class="music-page-header"><p class="music-kicker">MS-04 / Safe file handoff</p><h1 id="logicProTitle">Logic Pro X連携</h1><p>標準MIDIファイルを利用者が手動で受け渡す安全な入口です。Logic Proを起動・操作せず、プロジェクトファイルも編集しません。</p><span class="music-status is-working">案内・検証骨組み</span></header><section class="music-integration-grid"><article class="music-setting-section"><h2>現在の対応状況</h2><p><b>推奨：</b>Standard MIDI File Type 1を書き出し、Logic Proで手動読み込み。Logic ProからはMIDIを書き出し、Music Studioで確認後に取り込みコピーを作る方式です。</p><p class="music-help">今回はMIDI Composerと高度な解析が未実装です。MIDI・音声本体や履歴をプロジェクトJSONへ保存しません。</p></article><article class="music-setting-section"><h2>現在のプロジェクト</h2><p>${state.projects.length?`${state.projects.length}件あります。MIDIデータを持つ正式Composerは未実装です。`:'プロジェクトが選択されていません。連携の案内と設定確認は利用できます。'}</p><button class="music-primary" type="button" onclick="MusicStudio.requestMidiExport()">MIDIを書き出す</button></article></section><section class="music-setting-section"><h2>書き出し設定</h2>${settingSummary()}<button class="music-secondary" type="button" onclick="MusicStudio.goSettings()">Music Studio設定を開く</button></section><section class="music-integration-grid"><article class="music-setting-section"><h2>Logic ProからMIDIを読み込む</h2><p>.mid / .midi、16 MB以下を選択できます。先頭がStandard MIDI Fileか検証し、元ファイルと既存プロジェクトは変更しません。</p><input id="logicMidiImport" type="file" accept="audio/midi,audio/x-midi,.mid,.midi" onchange="MusicStudio.inspectMidiFile(this.files[0]);this.value=''" hidden><button class="music-secondary" type="button" onclick="document.querySelector('#logicMidiImport').click()">MIDIファイルを選ぶ</button><div id="logicMidiResult" class="music-file-result" aria-live="polite">解析履歴はまだありません。</div></article><article class="music-setting-section"><h2>音声ファイルを参照登録</h2><p>WAV、AIFF、CAFの名前・形式・容量だけを一時確認します。再読み込み後は再選択が必要で、絶対パスや本体は保存しません。</p><input id="logicAudioReference" type="file" accept="audio/wav,audio/x-wav,audio/aiff,audio/x-aiff,audio/x-caf,.wav,.wave,.aif,.aiff,.caf" onchange="MusicStudio.inspectAudioReference(this.files[0]);this.value=''" hidden><button class="music-secondary" type="button" onclick="document.querySelector('#logicAudioReference').click()">音声ファイルを選ぶ</button><div id="logicAudioResult" class="music-file-result" aria-live="polite">参照は登録されていません。</div></article></section><section class="music-setting-section"><h2>Logic Proでの読み込み手順</h2><ol class="music-steps">${LOGIC_IMPORT_STEPS.map(step=>`<li>${escapeHtml(step)}</li>`).join('')}</ol></section><section class="music-integration-grid"><article class="music-setting-section"><h2>対応形式</h2><p><b>受け渡し：</b>MIDI Type 0 / Type 1（Type 1推奨）</p><p><b>外部参照：</b>WAV / AIFF / CAF</p><p><b>補助資料：</b>JSON / テキスト（演奏データ用途ではありません）</p></article><article class="music-setting-section"><h2>今回の未対応</h2><p>MusicXML生成、音声生成、MIDI生成・高度解析、コード／ループの完全往復、Logicプロジェクト直接編集、自動起動・直接操作。</p><p class="music-help">iPad・iPhoneではファイル保存／選択は可能ですが、Logic Pro for Macへ渡す案内として使用してください。</p></article></section><section class="music-setting-section"><h2>書き出し・読み込み履歴</h2><p class="music-empty">履歴はまだありません。将来は日時、対象プロジェクト、形式、ファイル名、結果と警告だけを保存し、ファイル本体は保持しません。</p></section></main>`}
  function requestMidiExport(){notice('MIDI Composerが未実装で演奏データがないため、ファイルは作成しませんでした。空ファイルや壊れたMIDIは生成しません。','info')}
  function fileResult(id,message,kind='info'){const target=root.document?.querySelector(id);if(target){target.className=`music-file-result is-${kind}`;target.textContent=message}return{ok:kind==='success',message}}
  async function inspectMidiFile(file){if(!file)return{ok:false,cancelled:true,message:'ファイル選択をキャンセルしました。'};if(file.size>16*1024*1024)return fileResult('#logicMidiResult','16 MBを超えるため読み込めません。元ファイルは変更していません。','error');if(!/\.(?:mid|midi)$/i.test(file.name||''))return fileResult('#logicMidiResult','対応していない形式です。.mid または .midi を選択してください。','error');try{const bytes=new Uint8Array(await file.slice(0,4).arrayBuffer());if(bytes.length<4||String.fromCharCode(...bytes)!=='MThd')return fileResult('#logicMidiResult','Standard MIDI Fileのヘッダーを確認できません。壊れた可能性があるため拒否しました。','error');return fileResult('#logicMidiResult',`${file.name}（${byteLabel(file.size)}）を検証しました。高度な解析と保存は後続作業で行います。元ファイルは変更していません。`,'success')}catch(error){console.warn('Music Studio MIDI inspection failed',error);return fileResult('#logicMidiResult','ファイルを読み込めません。既存データは変更していません。','error')}}
  function inspectAudioReference(file){if(!file)return{ok:false,cancelled:true,message:'ファイル選択をキャンセルしました。'};if(!/\.(?:wav|wave|aif|aiff|caf)$/i.test(file.name||''))return fileResult('#logicAudioResult','対応していない形式です。WAV、AIFF、CAFを選択してください。','error');return fileResult('#logicAudioResult',`${file.name} / ${file.type||'形式情報なし'} / ${byteLabel(file.size)}。このタブ内で確認しただけで、本体・パスは保存していません。`,'success')}
  function placeholderView(route,options={}){const id=route.replace(`${HOME_ROUTE}/`,'');const item=FEATURES.find(feature=>feature.id===id&&!feature.action);if(!item)return homeView(options);return `<main class="music-studio-shell music-placeholder" aria-labelledby="musicPlaceholderTitle">${backButton()}<section class="music-placeholder-panel"><div class="music-card-top"><span class="music-feature-icon" aria-hidden="true">${escapeHtml(item.icon)}</span>${statusBadge(item.status)}</div><p class="music-kicker">Music Studio</p><h1 id="musicPlaceholderTitle">${escapeHtml(item.title)}</h1><p class="music-lead">${escapeHtml(item.description)}</p><p class="music-empty">この機能は今後のMS作業で実装します。現在は既存データを変更しない安全な準備中画面です。</p><button class="music-primary" onclick="MusicStudio.goHome()">ホームへ戻る</button></section></main>`}
  function parseEditId(route){return route.startsWith(`${EDIT_ROUTE}/`)?decodeURIComponent(route.slice(EDIT_ROUTE.length+1)):''}
  function renderRoute(route,options={}){if(route===HOME_ROUTE)return homeView(options);if(route===NEW_ROUTE)return createView();if(route===PROJECTS_ROUTE)return listView();if(route===SETTINGS_ROUTE)return settingsView();if(route===BACKUP_ROUTE)return backupView();if(route===LOGIC_PRO_ROUTE)return logicProView();const editId=parseEditId(route);if(editId)return editView(editId);return placeholderView(route,options)}
  function formValue(){const form=root.document?.querySelector('#musicProjectForm');if(!form)throw Error('フォームが見つかりません。');const get=name=>form.elements[name]?.value??'';return{projectName:get('projectName'),songTitle:get('songTitle'),purpose:get('purpose'),bpm:get('bpm'),timeSignature:get('timeSignature'),key:get('key'),status:get('status'),productionNotes:get('productionNotes')}}
  async function submitCreate(event){event?.preventDefault?.();try{const project=makeProject(formValue());const checked=validateProject(project);if(!checked.valid){notice(checked.errors.join(' '),'error');return}await repository.put(project);setLastProject(project.projectId);state.dirty=false;await refresh();notice('新しい音楽プロジェクトを保存しました。','success');routeTo(`${EDIT_ROUTE}/${encodeURIComponent(project.projectId)}`)}catch(error){console.error(error);notice('保存できませんでした。既存データは変更されていません。','error')}}
  async function submitEdit(event,id){event?.preventDefault?.();cancelScheduledSave();const result=await saveCurrentProject(id,true);if(result.ok){await refresh();notice('変更を保存しました。','success')}else notice(result.message||'保存できませんでした。入力内容は維持しています。','error')}
  async function duplicateProject(id){try{const source=await repository.get(id);if(!source)return;const timestamp=now();const duplicate={...clone(source),projectId:uuid(),projectName:`${source.projectName}（コピー）`,revision:1,createdAt:timestamp,updatedAt:timestamp};await repository.put(duplicate);setLastProject(duplicate.projectId);await refresh();notice('元のプロジェクトを変更せず複製しました。','success');routeTo(`${EDIT_ROUTE}/${encodeURIComponent(duplicate.projectId)}`)}catch(error){console.error(error);notice('複製できませんでした。','error')}}
  async function askDelete(id){const project=await repository.get(id);if(!project)return;const confirmed=root.confirm?.(`「${project.projectName}」を削除しますか？\nこの操作はこのプロジェクトだけに影響します。`)??false;if(!confirmed){notice('削除をキャンセルしました。','info');return}try{cancelScheduledSave();await repository.delete(id);if(getLastProject()===id)setLastProject('');state.dirty=false;await refresh();notice('プロジェクトを削除しました。ほかのプロジェクトは変更していません。','success');routeTo(PROJECTS_ROUTE)}catch(error){console.error(error);notice('削除できませんでした。','error')}}
  function safeFileName(name,maxLength=120,fallback='music-project'){const safe=String(name||'').normalize('NFKC').replace(/[\\/:*?"<>|\u0000-\u001f]/g,'-').replace(/[\s_-]+/g,'-').replace(/^[.\s-]+|[.\s-]+$/g,'').slice(0,maxLength);return safe||String(fallback||'music-project').normalize('NFKC').replace(/[\\/:*?"<>|\u0000-\u001f]/g,'-').slice(0,maxLength)||'music-project'}
  function fileNameTemplateErrors(template){const tokens=String(template||'').match(/\{[^}]+\}/g)||[];const allowed=new Set(['{projectName}','{songTitle}','{date}','{time}','{version}','{type}']);return [...new Set(tokens.filter(token=>!allowed.has(token)))].map(token=>`未対応トークン ${token} は使用できません。`)}
  function renderFileName(template,data={},options={}){const errors=fileNameTemplateErrors(template);if(errors.length)return{ok:false,errors,filename:''};const stamp=options.date instanceof Date?options.date:new Date(options.date||Date.now());const date=Number.isNaN(stamp.getTime())?'date':stamp.toISOString().slice(0,10);const time=Number.isNaN(stamp.getTime())?'time':stamp.toISOString().slice(11,19).replace(/:/g,'-');const values={projectName:data.projectName||'',songTitle:data.songTitle||'',type:data.type||'',date,time,version:data.version||APP_VERSION};const raw=String(template||'').replace(/\{(projectName|songTitle|type|date|time|version)\}/g,(_,key)=>values[key]);return{ok:true,errors:[],filename:safeFileName(raw,clampNumber(options.maxLength,20,200,120,true),options.fallback||'music-studio')}}
  async function exportProject(id){const project=await repository.get(id);if(!project)return;const exported={...clone(project),midiAssets:(project.midiAssets||[]).map(markExternal),audioAssets:(project.audioAssets||[]).map(markExternal),fileReferences:(project.fileReferences||[]).map(markExternal)};const text=JSON.stringify(exported,null,2);const date=now().slice(0,10);const filename=`${safeFileName(project.projectName)}-${date}.json`;if(!root.document||!root.Blob||!root.URL?.createObjectURL)return{filename,text};const url=root.URL.createObjectURL(new Blob([text],{type:'application/json'}));const link=root.document.createElement('a');link.href=url;link.download=filename;root.document.body.appendChild(link);link.click();link.remove();setTimeout(()=>root.URL.revokeObjectURL(url),1000);notice('JSONを書き出しました。MIDI・音声本体は含まれません。','success');return{filename,text}}
  function markExternal(asset){return{...clone(asset),storage:{...(asset.storage||{}),requiresReselection:true}}}
  async function importText(text){let parsed;try{parsed=JSON.parse(text)}catch(_){return{ok:false,message:'JSONが壊れているため読み込めません。既存データは変更していません。'}}const checked=validateProject(parsed);if(!checked.valid)return{ok:false,message:`読み込めません：${checked.errors.join(' ')}`};const incoming=clone(parsed);let duplicated=false;if(await repository.has(incoming.projectId)){incoming.projectId=uuid();incoming.projectName=`${incoming.projectName}（読み込み）`;incoming.createdAt=now();duplicated=true}incoming.updatedAt=now();incoming.revision=Math.max(1,Number(incoming.revision)||1);await repository.put(incoming);setLastProject(incoming.projectId);await refresh();return{ok:true,project:incoming,duplicated,message:duplicated?'ID重複を検出し、新しいIDで安全に読み込みました。':'プロジェクトを読み込みました。'}}
  async function importFile(file){if(!file)return;try{const result=await importText(await file.text());notice(result.message,result.ok?'success':'error');if(result.ok)routeTo(`${EDIT_ROUTE}/${encodeURIComponent(result.project.projectId)}`)}catch(error){console.error(error);notice('ファイルを読み込めません。既存データは変更していません。','error')}}
  function setPath(target,path,value){const parts=path.split('.');let cursor=target;for(const part of parts.slice(0,-1))cursor=cursor[part];cursor[parts.at(-1)]=value}
  function readSettingsForm(){const form=root.document?.querySelector('#musicSettingsForm');if(!form)throw Error('設定フォームが見つかりません。');const next=clone(state.settings||defaultSettings());for(const element of [...form.elements]){if(!element.name)continue;let value=element.type==='checkbox'?element.checked:element.value;if(element.type==='number')value=Number(value);if(element.name==='projectDefaults.key'&&!value)value=null;setPath(next,element.name,value)}next.logicPro.autoLaunch=false;next.logicPro.directControl=false;next.privacy.externalTransfer=false;next.privacy.usageData=false;next.privacy.analytics=false;next.privacy.cloudSync=false;next.privacy.localOnly=true;next.experimental.enabled=false;next.experimental.features={};return next}
  function settingsTemplateErrors(value){return fileNameTemplateErrors(value.fileNaming?.template)}
  async function persistSettings(input){const errors=settingsTemplateErrors(input);if(errors.length)return{ok:false,message:errors.join(' ')};const normalized=normalizeSettings({...input,updatedAt:now()});try{await repository.putSettings?.(normalized);state.settings=normalized;state.settingsDraft=clone(normalized);state.dirty=false;state.saveStatus='saved';configureAutosave();return{ok:true,settings:normalized,message:'設定を保存しました。'}}catch(error){console.error('Music Studio settings save failed',error);state.saveStatus='error';return{ok:false,message:'設定を保存できませんでした。現在の入力内容は維持しています。'}}}
  async function saveSettingsForm(event){event?.preventDefault?.();state.saveStatus='saving';const indicator=root.document?.querySelector('.music-save-state');if(indicator){indicator.dataset.status='saving';indicator.textContent='保存中'}try{const result=await persistSettings(readSettingsForm());notice(result.message,result.ok?'success':'error')}catch(error){console.error(error);state.saveStatus='error';notice('設定値を確認してください。現在の設定は変更していません。','error')}}
  function markSettingsDirty(){state.dirty=true;state.saveStatus='dirty';const indicator=root.document?.querySelector('.music-save-state');if(indicator){indicator.dataset.status='dirty';indicator.textContent='未保存の変更があります'}updateFileNamePreview()}
  function updateFileNamePreview(){const form=root.document?.querySelector('#musicSettingsForm'),output=root.document?.querySelector('#musicFileNamePreview');if(!form||!output)return;const result=renderFileName(form.elements['fileNaming.template']?.value,{projectName:'夜空のプロジェクト',songTitle:'星明かり',type:'midi'},{maxLength:form.elements['fileNaming.maxLength']?.value,fallback:form.elements['fileNaming.fallback']?.value,date:'2026-07-20T21:30:00.000Z'});output.textContent=result.ok?`プレビュー：${result.filename}.json`:`警告：${result.errors.join(' ')}`}
  function discardSettings(){if(state.dirty&&(root.confirm?.('未保存の設定変更を破棄しますか？')??false)===false)return;state.settingsDraft=clone(state.settings||defaultSettings());state.dirty=false;state.saveStatus='saved';requestPaint()}
  async function resetSettings(){if((root.confirm?.('Music Studio設定だけを初期値に戻しますか？\nプロジェクトデータは削除されません。')??false)===false)return;const createdAt=state.settings?.createdAt||now();const result=await persistSettings({...defaultSettings(),createdAt});notice(result.ok?'設定を初期値に戻しました。プロジェクトは変更していません。':result.message,result.ok?'success':'error')}
  function downloadJson(filename,value){const text=typeof value==='string'?value:JSON.stringify(value,null,2);if(!root.document||!root.Blob||!root.URL?.createObjectURL)return{filename,text};try{const url=root.URL.createObjectURL(new Blob([text],{type:'application/json'}));const link=root.document.createElement('a');link.href=url;link.download=filename;root.document.body.appendChild(link);link.click();link.remove();root.setTimeout?.(()=>root.URL.revokeObjectURL(url),1000);return{filename,text}}catch(error){console.error('Music Studio download failed',error);throw Error('JSONファイルを書き出せませんでした。')}
  }
  function exportSettings(){const value=normalizeSettings(state.settings||defaultSettings(),state.settings?.updatedAt||now());delete value.id;const result=downloadJson(`music-studio-settings_${now().slice(0,10)}.json`,value);notice('設定JSONを書き出しました。プロジェクトは含まれません。','success');return result}
  async function importSettingsText(text,confirmImport=false){let parsed;try{parsed=JSON.parse(text)}catch(_){return{ok:false,message:'設定JSONが壊れているため読み込めません。現在設定は維持しています。'}}const validation=validateSettings(parsed);if(!validation.valid)return{ok:false,message:`設定を読み込めません：${validation.errors.join(' ')}`};if(confirmImport&&(root.confirm?.('現在のMusic Studio設定を読み込んだ内容へ変更しますか？\nプロジェクトデータには影響しません。')??false)===false)return{ok:false,cancelled:true,message:'設定の読み込みをキャンセルしました。'};return persistSettings({...parsed,id:SETTINGS_ID,createdAt:state.settings?.createdAt||parsed.createdAt})}
  async function importSettingsFile(file){if(!file)return;try{const result=await importSettingsText(await file.text(),true);notice(result.message,result.ok?'success':result.cancelled?'info':'error')}catch(error){console.error(error);notice('設定ファイルを読み込めません。現在設定は維持しています。','error')}}
  function backupObject(){const projects=state.projects.map(project=>({...clone(project),midiAssets:(project.midiAssets||[]).map(markExternal),audioAssets:(project.audioAssets||[]).map(markExternal),fileReferences:(project.fileReferences||[]).map(markExternal)}));const references=projects.flatMap(project=>(project.fileReferences||[]).map(reference=>({projectId:project.projectId,...clone(reference)})));return{format:BACKUP_FORMAT,version:BACKUP_VERSION,metadata:{createdAt:now(),appVersion:APP_VERSION,projectCount:projects.length,settingsIncluded:true,binariesIncluded:false},settings:normalizeSettings(state.settings||defaultSettings()),projects,references}}
  function validateBackup(value){const errors=[],warnings=[];if(!value||typeof value!=='object'||Array.isArray(value))return{valid:false,errors:['JSONのルートがオブジェクトではありません。'],warnings};if(value.format!==BACKUP_FORMAT)errors.push(`形式は ${BACKUP_FORMAT} である必要があります。`);if(value.version!==BACKUP_VERSION)errors.push(`バックアップVersion ${value.version??'未設定'} には対応していません。`);if(!Array.isArray(value.projects))errors.push('projects配列がありません。');if(value.settings&&!validateSettings(value.settings).valid)warnings.push('設定形式が正しくないため、設定は復元対象から除外します。');if(Array.isArray(value.projects))value.projects.forEach((project,index)=>{if(!validateProject(project).valid)warnings.push(`プロジェクト${index+1}は不正なためスキップします。`)});return{valid:errors.length===0,errors,warnings}}
  function exportBackup(safety=false){const backup=backupObject();const prefix=safety?'music-studio-before-restore':'music-studio-backup';const result=downloadJson(`${prefix}_${now().slice(0,10)}.json`,backup);if(!safety)notice(`設定とプロジェクト${backup.projects.length}件のバックアップを書き出しました。実ファイル本体は含まれません。`,'success');return result}
  async function previewBackupText(text){let parsed;try{parsed=JSON.parse(text)}catch(_){return{ok:false,message:'バックアップJSONが壊れているため読み込めません。'}}const validation=validateBackup(parsed);if(!validation.valid)return{ok:false,message:`バックアップを読み込めません：${validation.errors.join(' ')}`};state.backupPreview=clone(parsed);requestPaint();return{ok:true,backup:parsed,warnings:validation.warnings,message:`バックアップを検証しました。内容を確認して復元してください。${validation.warnings.length?` 警告：${validation.warnings.join(' ')}`:''}`}}
  async function previewBackupFile(file){if(!file)return;try{const result=await previewBackupText(await file.text());notice(result.message,result.ok?'success':'error')}catch(error){console.error(error);notice('バックアップファイルを読み込めません。','error')}}
